void validateData(int row, int cells)
{
    int     i;

    for (i = 2; i<= cells; i++)
    {
        this.validateHeader(i);
    }
    if (conLen(conTestId) > 0)
        totalTest = conLen(conTestId);

    for (i = 2; i<= row; i++)
    {
        this.validateLine(i);
    }
}

void validateHeader(int col)
{
    InventTestId    headerValue = range.get_Item(1, col).Value;
    InventTestId    realTestId;
    InventTestTable tbl;
    str             normHeader, normTbl;

    normHeader = strLwr(KPMGCommon_ProcessImportQualityResults_OMT::removeAccents(headerValue));

    if (InventTestTable::exist(headerValue))
    {
        realTestId = headerValue;
    }
    else
    {
        while select tbl
        {
            normTbl = strLwr(KPMGCommon_ProcessImportQualityResults_OMT::removeAccents(tbl.TestId));
            if (normTbl == normHeader)
            {
                realTestId = tbl.TestId;
                break;
            }
        }
    }

    conTestId = conIns(conTestId, col - 1, realTestId);

    if (!realTestId)
    {
        if (errormessage)
            errormessage += "\n";
        errormessage += strFmt("@KPMGCommon:InterfaceImportingQualityResultsErrorHeader", headerValue);
    }
}

public static str removeAccents(str input)
{
    str s = input;
    s = strReplace(s, 'á', 'a'); s = strReplace(s, 'Á', 'A');
    s = strReplace(s, 'é', 'e'); s = strReplace(s, 'É', 'E');
    s = strReplace(s, 'í', 'i'); s = strReplace(s, 'Í', 'I');
    s = strReplace(s, 'ó', 'o'); s = strReplace(s, 'Ó', 'O');
    s = strReplace(s, 'ú', 'u'); s = strReplace(s, 'Ú', 'U');
    s = strReplace(s, 'ñ', 'n'); s = strReplace(s, 'Ñ', 'N');
    return s;
}

void validateLine(int row)
{
    InventQualityOrderId    inventQualityOrderId;
    InventQualityOrderTable inventQualityOrderTable;
    InventQualityOrderLine  inventQualityOrderLine;
    int                     i;

    inventQualityOrderId = range.get_Item(row, 1).Value;
    inventQualityOrderTable = InventQualityOrderTable::find(inventQualityOrderId);
    if (!inventQualityOrderTable)
    {
        if (errormessage)
            errormessage += " /n";

        errormessage += strFmt("@KPMGCommon:InterfaceImportingQualityResultsErrorLine1", row, inventQualityOrderId); //Lìnea %1 - Pedido de Calidad %2 no existe.
    }
    else if(inventQualityOrderTaBle && inventQualityOrderTable.OrderStatus != InventTestOrderStatus::Open)
    {
        if (errormessage)
            errormessage += " /n";

        errormessage += strFmt("@KPMGCommon:InterfaceImportingQualityResultsErrorLine2", row, inventQualityOrderId); //Línea %1 - Pedido de Calidad %2 no está Abierto.
    }


    for (i = 1; i<= totalTest; i++)
    {
        select firstonly inventQualityOrderLine
        where inventQualityOrderLine.QualityOrderId == inventQualityOrderId
           && inventQualityOrderLine.TestId == conPeek(conTestId, i);
        if (!inventQualityOrderLine)
        {
            if (errormessage)
                errormessage += " /n";

            errormessage += strFmt("@KPMGCommon:InterfaceImportingQualityResultsErrorLine3", row, inventQualityOrderId, conPeek(conTestId, i)); //Línea %1 - Pedido de Calidad %2 no existe línea para prueba %3.
        }
    }

    if (errormessage)
        lineerror++;
}

void create(int row)
{
    InventTestId                inventTestId;
    InventQualityOrderId        inventQualityOrderId;
    InventQualityOrderTable     inventQualityOrderTable;
    InventQualityOrderValidate  inventQualityOrderValidate = InventQualityOrderValidate::construct();
    int                         column, i;
    Args                        args = new Args();
    MenuFunction                menuFunction;

    inventQualityOrderId = range.get_Item(row, 1).Value;

    try
    {
        inventQualityOrderTable = InventQualityOrderTable::find(inventQualityOrderId);
        for (i = 1; i<= totalTest; i++)
        {
            column = i + 1;
            inventTestId = conPeek(conTestId, i);

            this.createResults(row, column, inventQualityOrderTable, inventTestId);
        }

        /*
        inventQualityOrderValidate.initFromQualityOrderTable(inventQualityOrderTable);
        inventQualityOrderValidate.parmQualityOrderId(inventQualityOrderTable.QualityOrderId);
        inventQualityOrderValidate.parmWorker(fieldWorker.value());
        inventQualityOrderValidate.parmAcceptError(fieldAcceptError.value());
        inventQualityOrderValidate.run();
        */

        this.ValidateQualityId(inventQualityOrderTable);
    }
    catch
    {
        lineerror++;
        ttsAbort;
    }
}

void ValidateQualityId(InventQualityOrderTable     inventQualityOrderTable)
{
    Args            args = new Args();
    MenuFunction    menuFunction;

    args.record(inventQualityOrderTable);
    menuFunction = new MenuFunction(menuitemActionStr(InventQualityOrderValidate), MenuItemType::Action);

    if (menuFunction && menuFunction.checkAccessRights())
        menuFunction.run(args);

}

void createResults(int row, int column, InventQualityOrderTable _InventQualityOrderTable, InventTestId _InventTestId)
{
    InventQualityOrderLineResultReal    testResultValueReal;
    InventTestVariableOutcomeId         testResultValueOutcome;
    InventQualityOrderLine              inventQualityOrderLine;
    InventQualityOrderLineResults       inventQualityOrderLineResults, inventQualityOrderLineResultsExists;

    if (InventTestTable::find(_InventTestId).TestType == InventTestType::Option)
    {
        testResultValueOutcome = range.get_Item(row, column).Value;
    }
    else
    {
        testResultValueReal = range.get_Item(row, column).Value;
    }

    ttsbegin;
    select firstonly forupdate inventQualityOrderLine
        where inventQualityOrderLine.QualityOrderId == _InventQualityOrderTable.QualityOrderId
           && inventQualityOrderLine.TestId == _InventTestId;
    if (inventQualityOrderLine)
    {
        select firstonly forupdate inventQualityOrderLineResultsExists
            where inventQualityOrderLineResultsExists.QualityOrderId == inventQualityOrderLine.QualityOrderId
               && inventQualityOrderLineResultsExists.TestSequence == inventQualityOrderLine.TestSequence
               && inventQualityOrderLineResultsExists.TestId == inventQualityOrderLine.TestId;
        if (inventQualityOrderLineResultsExists)
        {
            inventQualityOrderLineResultsExists.TestResultValueReal = testResultValueReal;
            inventQualityOrderLineResultsExists.TestResultValueOutcome = TestResultValueOutcome;
            inventQualityOrderLineResultsExists.TestResultQuantity = _InventQualityOrderTable.Qty;
            inventQualityOrderLineResultsExists.PdsCWTestResultQuantity = _InventQualityOrderTable.PdsCWQty;
            inventQualityOrderLineResultsExists.setTestResult(inventQualityOrderLine, false);
            inventQualityOrderLineResultsExists.update();
        }
        else
        {
            inventQualityOrderLineResults.clear();
            inventQualityOrderLineResults.initValue();
            inventQualityOrderLineResults.initFromInventQualityOrderLine(inventQualityOrderLine);
            inventQualityOrderLineResults.TestResultValueReal = testResultValueReal;
            inventQualityOrderLineResults.TestResultValueOutcome = TestResultValueOutcome;
            inventQualityOrderLineResults.TestResultQuantity = _InventQualityOrderTable.Qty;
            inventQualityOrderLineResults.PdsCWTestResultQuantity = _InventQualityOrderTable.PdsCWQty;
            inventQualityOrderLineResults.setTestResult(inventQualityOrderLine, false);
            inventQualityOrderLineResults.insert();
        }

        inventQualityOrderLine.setTestResult();
        inventQualityOrderLine.update();
    }
    ttscommit;
}

void import()
{
    Container               con;
    ;

    setPrefix("@KPMGCommon:ImportQualityResultsOMT"); //Importación de Resultados de Calidad para OMT

    if (this.openFile())
    {
        using (ExcelPackage Package = new ExcelPackage(stream))
        {
            int                         rowCount, i, endRow, startRow, cellsCount, endCells, startCells;
            Package.Load(stream);
            ExcelWorksheet  worksheet   = package.get_Workbook().get_Worksheets().get_Item(1);
            range       = worksheet.Cells;
            endRow      = worksheet.Dimension.End.Row;
            startRow    = worksheet.Dimension.Start.Row;
            rowCount    = endRow - startRow + 1;
            endCells   = worksheet.Dimension.End.Column;
            startCells    = worksheet.Dimension.Start.Column;
            cellsCount    = endCells - startCells + 1;

            try
            {
                this.validateData(rowCount, cellsCount);

                if (!errormessage)
                {
                    for (i = 2; i<= rowCount; i++)
                    {
                        setPrefix(strFmt("Line %1", i));
                        this.create(i);
                        lineimported++;
                    }
                }
                else
                {
                    throw error(strFmt("Errores: %1", errormessage));
                }
            }
            catch
            {
                throw error("Error - Import template");
            }
        }
    }

    info(strfmt("%1 record(s) imported", lineimported));
    info(strfmt("%1 record(s) fail", lineerror));
}

boolean openFile()
{
    boolean ret = false;

    if (fileUploadResult != null && fileUploadResult.getUploadStatus())
    {
        stream = fileUploadResult.openResult();
        ret = true;
    }
    else
    {
        throw error(strfmt("@SYS62207",filename));
    }

    return ret;
}

