    fieldWorker.value(hcmWorker::userId2Worker(curUserId()));
    fieldAcceptError = dialog.addFieldValue(enumStr(NoYes), acceptError, "@SYS14646", "@SYS113891");
    fieldAcceptError.registerOverrideMethod(
        methodStr(FormCheckBoxControl, modified),
        methodStr(InventQualityOrderValidate, acceptError_modified),
        this);
    */
    return dialog;
}

/// <summary>
/// Disables the dialog Ok button until the file upload is complete.
/// </summary>
/// <param name="_dialog">The <c>Runbase</c> dialog object.</param>
public void dialogPostRun(DialogRunbase _dialog)
{
    fileUpload = _dialog.formRun().control(_dialog.formRun().controlId('FileUpload'));
    fileUpload.notifyUploadCompleted += eventhandler(this.uploadCompleted);
    this.setDialogOkButtonEnabled(_dialog, false);
}

/// <summary>
/// After the file has been uploaded, the Ok button is enabled.
/// </summary>
public void uploadCompleted()
{
    filename = fileUpload.fileName();

    this.setDialogOkButtonEnabled(dialog, true);

    fileUploadResult = fileUpload.getFileUploadResult();

    fileUpload.notifyUploadCompleted -= eventhandler(this.UploadCompleted);
}

/// <summary>
/// Enables or disables the dialog Ok button.
/// </summary>
/// <param name = "_dialog">The <c>Runbase</c> dialog object.</param>
/// <param name = "_isEnabled">Indicates to enable or disable the Ok button.</param>
protected void setDialogOkButtonEnabled(DialogRunbase _dialog, boolean _isEnabled)
{
    FormControl okButtonControl = _dialog.formRun().control(_dialog.formRun().controlId('OkButton'));

    if (okButtonControl)
    {
        okButtonControl.enabled(_isEnabled);
    }
}

public boolean unpack(container packedClass)
{
    Version version = runbase::getVersion(packedClass);
    ;
    switch (version)
    {
        case #CurrentVersion:
            [version,#CurrentList] = packedClass;
            break;
        default:
            return false;
    }
    return true;
}

static void main(Args _args)
{
    KPMGCommon_ProcessImportQualityResults_OMT   import = new KPMGCommon_ProcessImportQualityResults_OMT();
    FormRun formRun;
    Args    args;
    ;

    if (import.prompt())
    {
        import.run();
    }
}

public ClassDescription caption()
{
    return "@KPMGCommon:ImportQualityResultsOMT"; //Importación de Resultados de Calidad para OMT
}
